import 'package:flutter/material.dart';import 'package:get/get.dart';import '../../common/app_card.dart';import '../../common/app_motion.dart';import '../../common/loading_state.dart';import '../../common/responsive.dart';import '../../controllers/profile_controller.dart';
class ProgressView extends StatefulWidget{const ProgressView({super.key});@override State<ProgressView> createState()=>_ProgressViewState();}class _ProgressViewState extends State<ProgressView>{@override void initState(){super.initState();WidgetsBinding.instance.addPostFrameCallback((_){if(mounted)Get.find<ProfileController>().load();});}@override Widget build(BuildContext context){final c=Get.find<ProfileController>();return Scaffold(appBar:AppBar(title:const Text('Progress')),body:PageShell(child:Obx(()=>c.loading.value?const LoadingState():GameListView(children:[AppCard(child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text('Current position',style:Theme.of(context).textTheme.titleLarge),const SizedBox(height:12),Text('Level ${c.progress.value.levelOrder} • Unit ${c.progress.value.unitOrder} • Task ${c.progress.value.taskOrder} • Lesson ${c.progress.value.lessonOrder}'),const SizedBox(height:12),LinearProgressIndicator(value:(c.progress.value.lessonOrder.clamp(1,10))/10)])),AppCard(child:ListTile(title:const Text('Achievement'),subtitle:Text(c.progress.value.achievement.isEmpty?'Keep going — your next achievement is close.':c.progress.value.achievement),leading:const Icon(Icons.emoji_events_rounded)))]))));}}
